  .co-micon{font-size:24px;margin-bottom:6px;}
  .co-mname{font-size:13px;font-weight:600;color:var(--text);margin-bottom:3px;}
  .co-msub{font-size:10px;color:var(--muted);line-height:1.4;}

  /* ── Security ── */
  .co-sec{display:flex;gap:8px;justify-content:center;flex-wrap:wrap;margin:20px 0 12px;}
  .co-badge{
    padding:5px 13px;border-radius:50px;font-size:10px;font-weight:600;
    background:var(--sage-xs);color:var(--sage);
    border:1px solid var(--border);letter-spacing:0.4px;font-family:'Outfit',sans-serif;
  }
  .co-powered{text-align:center;font-size:11px;color:var(--muted);font-family:'Outfit',sans-serif;}
  .co-powered strong{color:var(--sage-d);}

  /* ── Back Button ── */
  .co-back{
    display:block;width:100%;background:none;border:none;
    color:var(--muted);font-size:12px;cursor:pointer;
    text-align:center;padding:14px;font-family:'Outfit',sans-serif;
    letter-spacing:1.5px;text-transform:uppercase;transition:color 0.2s;
  }
  .co-back:hover{color:var(--sage);}

  /* ── Success Screen ── */
  .co-success-outer{
    min-height:100vh;background:var(--bg);display:flex;flex-direction:column;
  }
  .co-success-hero{
    background:linear-gradient(160deg,#1e3a28,#2a5a3c,#1a4030);
    padding:80px 24px 60px;text-align:center;position:relative;overflow:hidden;
  }
  .co-success-wrap{
    max-width:480px;margin:0 auto;padding:40px 20px 80px;
    animation:popIn 0.5s cubic-bezier(.34,1.56,.64,1);
  }
  .co-s-card{
    background:var(--surface);border:1px solid var(--border);
    border-radius:var(--radius);padding:40px 28px;
    box-shadow:var(--shadow-lg);margin-top:-40px;position:relative;z-index:2;
  }
  .co-s-emoji{font-size:70px;display:block;margin-bottom:16px;animation:floatY 2s ease-in-out infinite;}
  .co-s-label{
    display:inline-flex;align-items:center;gap:8px;
    font-size:0.68rem;font-weight:700;letter-spacing:0.22em;text-transform:uppercase;
    color:var(--sage);margin-bottom:10px;
  }
  .co-s-label::before{content:'';width:24px;height:2px;background:var(--sage);border-radius:2px;}
  .co-s-title{
    font-family:'Cormorant Garamond',serif;
    font-size:34px;font-weight:700;color:var(--sage-d);margin-bottom:6px;
  }
  .co-s-amt{font-size:14px;color:var(--muted);margin-bottom:26px;}
  .co-pid{
    background:var(--sage-xs);border:1px solid var(--border);border-radius:10px;
    padding:12px 16px;margin-bottom:26px;font-size:11px;color:var(--sage);
    word-break:break-all;font-family:'Outfit',sans-serif;line-height:1.6;
  }
  .co-btn-row{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;}
  .co-gbtn{
    padding:13px 24px;background:var(--sage);color:#fff;border:none;
    border-radius:50px;font-family:'Outfit',sans-serif;font-weight:700;
    font-size:14px;cursor:pointer;transition:all 0.22s;
  }
  .co-obtn{
    padding:13px 24px;background:transparent;color:var(--sage);
    border:1.5px solid var(--border);border-radius:50px;
    font-family:'Outfit',sans-serif;font-weight:700;font-size:14px;
    cursor:pointer;transition:all 0.22s;
  }
  .co-gbtn:hover{background:var(--sage-d);transform:translateY(-2px);box-shadow:0 8px 20px rgba(61,107,79,0.28);}
  .co-obtn:hover{border-color:var(--sage);background:var(--sage-xs);transform:translateY(-2px);}

  /* ── Trust Strip ── */
  .co-trust{
    background:var(--ivory);border-top:1px solid var(--border);
    padding:20px 24px;display:flex;justify-content:center;
    gap:28px;flex-wrap:wrap;margin-top:8px;
  }
  .co-trust-item{display:flex;align-items:center;gap:6px;font-size:11px;color:var(--muted);font-family:'Outfit',sans-serif;}
  .co-trust-icon{font-size:15px;}

  /* ── Toast ── */
  .co-toast{
    position:fixed;bottom:28px;left:50%;
    transform:translateX(-50%) translateY(100px);
    background:var(--text);border:1px solid var(--border);
    border-radius:50px;padding:11px 22px;
    color:#fff;font-size:13px;font-weight:500;
    box-shadow:var(--shadow-lg);z-index:9999;
    transition:transform 0.3s ease;white-space:nowrap;
    font-family:'Outfit',sans-serif;
  }
  .co-toast.show{transform:translateX(-50%) translateY(0);}

  @media(max-width:480px){
    .co-hero{padding:44px 16px 38px;}
    .co-wrap{padding:24px 12px 60px;}
    .co-pay-card,.co-amount-card{padding:22px 18px;}
    .co-amount-meta{gap:14px;}
  }
