import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import Nav from "./Nev";

// ─── CONFIG ──────────────────────────────────────────────────
const RAZORPAY_KEY_ID = "rzp_test_Sq7J7mRZo6zCD1";
const MERCHANT_UPI    = "dharmesh.220180107013@okhdfcbank";
const MERCHANT_NAME   = "Petology Pet Shop";
// ─────────────────────────────────────────────────────────────

const UPI_APPS = [
  {
    id: "gpay", name: "Google Pay", color: "#4285F4", bg: "#e8f0fe", label: "G",
    labelStyle: { background: "linear-gradient(135deg,#4285F4,#34A853,#FBBC05,#EA4335)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", fontWeight: 900, fontSize: 20 },
    getLink: (upi, amt, note) => `tez://upi/pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
  {
    id: "phonepe", name: "PhonePe", color: "#5f259f", bg: "#f3e8ff", label: "Pe",
    labelStyle: { color: "#5f259f", fontWeight: 900, fontSize: 18 },
    getLink: (upi, amt, note) => `phonepe://pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
  {
    id: "paytm", name: "Paytm", color: "#00BAF2", bg: "#e0f7fe", label: "PT",
    labelStyle: { color: "#00BAF2", fontWeight: 900, fontSize: 16 },
    getLink: (upi, amt, note) => `paytmmp://upi/pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
  {
    id: "bhim", name: "BHIM UPI", color: "#e84141", bg: "#fee2e2", label: "B",
    labelStyle: { color: "#e84141", fontWeight: 900, fontSize: 20 },
    getLink: (upi, amt, note) => `upi://pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
];

// ─── QR Code Component ───────────────────────────────────────
function UpiQR({ upiString, size = 200 }) {
  const canvasRef = useRef(null);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    if (window.qrcode) { drawQR(); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js";
    s.onload = drawQR;
    document.head.appendChild(s);
  }, [upiString]);

  function drawQR() {
    const div = document.createElement("div");
    div.style.display = "none";
    document.body.appendChild(div);
    try {
      new QRCode(div, {
        text: upiString, width: size, height: size,
        colorDark: "#1c2b22", colorLight: "#ffffff",
        correctLevel: window.QRCode?.CorrectLevel?.H || 1,
      });
      setTimeout(() => {
        const img = div.querySelector("img");
        const canvas = canvasRef.current;
        if (!canvas || !img) return;
        const ctx = canvas.getContext("2d");
        const image = new Image();
        image.onload = () => { ctx.drawImage(image, 0, 0, size, size); setLoaded(true); };
        image.src = img.src;
        document.body.removeChild(div);
      }, 300);
    } catch (e) { document.body.removeChild(div); }
  }

  return (
    <div style={{ position: "relative", width: size, height: size }}>
      {!loaded && (
        <div style={{
          position: "absolute", inset: 0, display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center",
          background: "#fdf9f2", borderRadius: 16, gap: 10,
        }}>
          <div style={{
            width: 32, height: 32, border: "2.5px solid #3d6b4f",
            borderTopColor: "transparent", borderRadius: "50%",
            animation: "spinR 0.8s linear infinite",
          }} />
          <span style={{ fontSize: 11, color: "#7a907f", fontFamily: "'Outfit', sans-serif" }}>Generating QR…</span>
        </div>
      )}
      <canvas ref={canvasRef} width={size} height={size}
        style={{ borderRadius: 14, display: loaded ? "block" : "none" }} />
    </div>
  );
}

// ─── CSS ─────────────────────────────────────────────────────
const css = `
  @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,700&family=Outfit:wght@300;400;500;600;700&display=swap');

  :root {
    --bg:       #f4f1eb;
    --bg2:      #ede8de;
    --surface:  #ffffff;
    --card:     #faf8f4;
    --sage:     #3d6b4f;
    --sage-d:   #2a4e39;
    --sage-l:   #5a9470;
    --sage-xs:  rgba(61,107,79,0.09);
    --sage-sm:  rgba(61,107,79,0.18);
    --gold:     #b8922a;
    --gold-l:   #d4ac48;
    --gold-xs:  rgba(184,146,42,0.12);
    --border:   rgba(61,107,79,0.13);
    --border2:  rgba(184,146,42,0.18);
    --text:     #1c2b22;
    --text2:    #3a4a3f;
    --muted:    #7a907f;
    --dim:      #aab8ac;
    --ivory:    #fdf9f2;
    --shadow:   0 4px 24px rgba(30,50,35,0.08);
    --shadow-lg:0 16px 60px rgba(30,50,35,0.14);
    --radius:   20px;
  }

  *{box-sizing:border-box;margin:0;padding:0;}
  ::-webkit-scrollbar{width:5px;}
  ::-webkit-scrollbar-thumb{background:var(--sage);border-radius:10px;}

