// ─── Main Component ───────────────────────────────────────────
export default function Checkout() {
  const [tab, setTab]                 = useState("upi");
  const [selectedApp, setSelectedApp] = useState(null);
  const [customUpi, setCustomUpi]     = useState("");
  const [loading, setLoading]         = useState(false);
  const [done, setDone]               = useState(false);
  const [paymentId, setPaymentId]     = useState("");
  const [toast, setToast]             = useState("");
  const [showToast, setShowToast]     = useState(false);

  const amount    = parseInt(localStorage.getItem("item") || 0);
  const uid       = localStorage.getItem("id") || 0;
  const userName  = localStorage.getItem("uname") || "Customer";
  const userEmail = localStorage.getItem("email") || "customer@example.com";
  const navigate  = useNavigate();

  const upiQrString = `upi://pay?pa=${MERCHANT_UPI}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amount}&cu=INR&tn=${encodeURIComponent("Petology Order")}`;

  // Scroll reveal
  useEffect(() => {
    const els = document.querySelectorAll(".reveal");
    const obs = new IntersectionObserver((entries) => {
      entries.forEach((e) => { if (e.isIntersecting) e.target.classList.add("visible"); });
    }, { threshold: 0.12 });
    els.forEach((el) => obs.observe(el));
    return () => obs.disconnect();
  }, [done]);

  useEffect(() => {
    if (!localStorage.getItem("islogin")) { navigate("/login"); return; }
    const s = document.createElement("script");
    s.src = "https://checkout.razorpay.com/v1/checkout.js";
    document.body.appendChild(s);
  }, []);

  const msg = (text) => {
    setToast(text); setShowToast(true);
    setTimeout(() => setShowToast(false), 3200);
  };

  const clearCart = () =>
    fetch("http://localhost/Petshop/deletecart.php?uid=" + uid).catch(() => {});

  const saveOrder = (oid) =>
    axios({
      method: "POST", url: "http://localhost/Petshop/order.php",
      data: { pid: localStorage.getItem("pid") || 1, order_id: oid, uid, totalitem: localStorage.getItem("totalitem") || 1, amount },
      headers: { "Content-Type": "multipart/form-data" },
    }).catch(() => {});

  const success = (pid) => {
    setPaymentId(pid); saveOrder(pid); clearCart(); setDone(true); setLoading(false);
  };

  const handleRazorpay = () => {
    if (!window.Razorpay) { msg("⚠️ Page reload karein"); return; }
    setLoading(true);
    const rzp = new window.Razorpay({
      key: RAZORPAY_KEY_ID, amount: amount * 100, currency: "INR",
      name: MERCHANT_NAME, description: "Pet Purchase", image: "https://i.imgur.com/n5tjHFD.png",
      handler: (r) => success(r.razorpay_payment_id),
      prefill: { name: userName, email: userEmail },
      theme: { color: "#3d6b4f" },
      modal: { ondismiss: () => setLoading(false) },
    });
    rzp.on("payment.failed", (r) => { setLoading(false); msg("❌ " + r.error.description); });
    rzp.open();
  };

  const handleUpiApp = (app) => {
    const note = encodeURIComponent("Petology Order");
    msg(`Opening ${app.name}…`);
    window.location.href = app.getLink(MERCHANT_UPI, amount, note);
    setTimeout(() => success("UPI_" + Date.now()), 9000);
  };

  const handleCustomUpi = () => {
    if (!customUpi.includes("@")) { msg("⚠️ Valid UPI ID daalo (ex: name@upi)"); return; }
    window.location.href = `upi://pay?pa=${customUpi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amount}&cu=INR&tn=PetologyOrder`;
    msg("Opening UPI app…");
  };

  const handleQrConfirm = () => {
    success("QR_" + Date.now());
  };

  const selApp = UPI_APPS.find((a) => a.id === selectedApp);

  // ── SUCCESS SCREEN ─────────────────────────────────────────
  if (done) return (
    <>
      <style>{css}</style>
      <div className="co-success-outer">
        <Nav />
        <div className="co-success-hero">
          <div className="co-hero-orb co-hero-orb1" />
          <div className="co-hero-orb co-hero-orb2" />
          <div style={{ position: "relative", zIndex: 1 }}>
            <div className="co-hero-label">Order Confirmed</div>
            <h1 style={{
              fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(28px,6vw,40px)",
              fontWeight: 700, color: "#fff", lineHeight: 1.1,
            }}>
              Thank You for<br />Choosing Petology 🐾
            </h1>
          </div>
        </div>

        <div className="co-success-wrap">
          <div className="co-s-card">
            <span className="co-s-emoji">🎉</span>
            <div className="co-s-label">Payment Successful</div>
            <div className="co-s-title">Order Placed!</div>
            <div className="co-s-amt">₹{amount.toLocaleString("en-IN")} paid successfully</div>
            <div className="co-pid">
              <strong>Payment ID:</strong> {paymentId}<br />
              <span style={{ color: "var(--muted)", fontSize: 10 }}>Save this for your records</span>
            </div>
            <div className="co-btn-row">
              <button className="co-gbtn" onClick={() => navigate("/myorder")}>📦 My Orders</button>
              <button className="co-obtn" onClick={() => navigate("/product")}>🐾 Shop More</button>
            </div>
          </div>

          <div className="co-trust">
            {["🚚 Free Delivery", "📦 Track Your Order", "💚 Happy Pets Guaranteed"].map((t, i) => (
              <div className="co-trust-item" key={i}>
                <span className="co-trust-icon">{t.split(" ")[0]}</span>
                <span>{t.split(" ").slice(1).join(" ")}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
      <div className={`co-toast ${showToast ? "show" : ""}`}>{toast}</div>
    </>
  );

  // ── MAIN CHECKOUT ──────────────────────────────────────────
  return (
    <>
      <style>{css}</style>
      <div className="co-page">
        <Nav />

        {/* Hero */}
        <div className="co-hero">
          <div className="co-hero-orb co-hero-orb1" />
          <div className="co-hero-orb co-hero-orb2" />
          <div style={{ position: "relative", zIndex: 1 }}>
            <div className="co-hero-breadcrumb">
              Home / Cart / <span>Checkout</span>
            </div>
            <div className="co-hero-label">Secure Checkout</div>
            <h1 className="co-hero-title">Complete Your<br />Purchase</h1>
            <p className="co-hero-sub">Safe · Fast · Trusted by 50,000+ Pet Parents</p>
            <div className="co-hero-badges">
              <span className="co-hero-badge green">🔒 256-bit SSL</span>
              <span className="co-hero-badge">✅ RBI Approved</span>
              <span className="co-hero-badge">🛡️ PCI DSS</span>
              <span className="co-hero-badge">⚡ Instant Confirmation</span>
            </div>
          </div>
        </div>

        <div className="co-wrap">

          {/* Amount Card */}
          <div className="co-amount-card reveal">
            <div className="co-amount-inner">
              <div>
                <div className="co-amount-label">Total Payable Amount</div>
                <div className="co-amount-value">
                  <em>₹</em>{amount.toLocaleString("en-IN")}
                </div>
                <div className="co-amount-free">✅ Free delivery included</div>
              </div>
              <div className="co-amount-pet">🐾</div>
            </div>
            <div className="co-amount-meta">
              <div className="co-meta-item">
                <span className="co-meta-label">Customer</span>
                <span className="co-meta-val">{userName}</span>
              </div>
              <div className="co-meta-item">
                <span className="co-meta-label">Items</span>
                <span className="co-meta-val">{localStorage.getItem("totalitem") || 1} item(s)</span>
              </div>
              <div className="co-meta-item">
                <span className="co-meta-label">Delivery</span>
                <span className="co-meta-val" style={{ color: "var(--sage-l)" }}>FREE</span>
              </div>
            </div>
          </div>

          {/* Payment Card */}
          <div className="co-pay-card reveal">
            <div className="co-section-eye">Payment Method</div>
            <div className="co-section-title">How would you like to pay?</div>

            {/* Tabs */}
            <div className="co-tabs">
              {[
                { id: "upi",  icon: "📲", label: "UPI Apps" },
                { id: "qr",   icon: "▣",  label: "QR Code"  },
                { id: "card", icon: "💳", label: "Card/Bank" },
              ].map((t) => (
                <button
                  key={t.id}
                  className={`co-tab ${tab === t.id ? "active" : ""}`}
                  onClick={() => setTab(t.id)}
                >
                  <span className="co-tab-icon">{t.icon}</span>
                  {t.label}
                </button>
              ))}
            </div>

            {/* ══ UPI APPS ══ */}
            {tab === "upi" && <>
              <div className="co-upi-grid">
                {UPI_APPS.map((app) => (
                  <button
                    key={app.id}
                    className={`co-upi-btn ${selectedApp === app.id ? "sel" : ""}`}
                    onClick={() => setSelectedApp(app.id)}
                  >
                    <div className="co-upi-icon" style={{ background: app.bg }}>
                      <span style={app.labelStyle}>{app.label}</span>
                    </div>
                    <span className="co-upi-name">{app.name}</span>
                    <div className="co-tick">✓</div>
                  </button>
                ))}
              </div>

              {selApp && (
                <button className="co-open-btn" onClick={() => handleUpiApp(selApp)}>
                  Open {selApp.name} → Pay ₹{amount.toLocaleString("en-IN")}
                </button>
              )}

              <div className="co-or">or enter UPI ID manually</div>
              <input
                className="co-input"
                placeholder="yourname@okaxis  /  9876543210@upi"
                value={customUpi}
                onChange={(e) => setCustomUpi(e.target.value)}
              />
              <div className="co-input-hint">Works with GPay, PhonePe, Paytm, BHIM & all UPI apps</div>
              {customUpi.includes("@") && (
                <button className="co-pay-btn" onClick={handleCustomUpi}>
                  💸 Pay ₹{amount.toLocaleString("en-IN")} via UPI ID
                </button>
              )}
            </>}

            {/* ══ QR CODE ══ */}
            {tab === "qr" && (
              <div className="co-qr-wrap">
                <div className="co-qr-eye">Scan & Pay</div>
                <div className="co-qr-title">Any UPI App, Instantly</div>
                <div className="co-qr-sub">Open any UPI app → Scan → Pay in seconds</div>

                <div className="co-qr-apps">
                  {[
                    { label: "G",  style: { background: "linear-gradient(135deg,#4285F4,#34A853,#FBBC05,#EA4335)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", fontWeight: 900 }, bg: "#e8f0fe", name: "GPay" },
                    { label: "Pe", style: { color: "#5f259f", fontWeight: 900 }, bg: "#f3e8ff", name: "PhonePe" },
                    { label: "PT", style: { color: "#00BAF2", fontWeight: 900 }, bg: "#e0f7fe", name: "Paytm" },
                    { label: "B",  style: { color: "#e84141", fontWeight: 900 }, bg: "#fee2e2", name: "BHIM" },
                  ].map((a, i) => (
                    <div className="co-qr-app" key={i}>
                      <div className="co-qr-app-icon" style={{ background: a.bg }}>
                        <span style={a.style}>{a.label}</span>
                      </div>
                      <span>{a.name}</span>
                    </div>
                  ))}
                </div>

                <div className="co-qr-box">
                  <div className="co-qr-corner co-qr-tl" />
                  <div className="co-qr-corner co-qr-tr" />
                  <div className="co-qr-corner co-qr-bl" />
                  <div className="co-qr-corner co-qr-br" />
                  <UpiQR upiString={upiQrString} size={200} />
                </div>

                <div className="co-qr-upi">
                  Pay to: <strong>{MERCHANT_UPI}</strong><br />
                  Amount: <strong>₹{amount.toLocaleString("en-IN")}</strong>
                </div>

                <div className="co-steps">
                  {[
                    "Open GPay / PhonePe / Paytm / BHIM",
                    "Tap 'Scan QR' or 'Pay by QR'",
                    "Scan this QR code",
                    "Amount auto-fills — Confirm payment",
                    "Tap 'I have paid' button below",
                  ].map((step, i) => (
                    <div className="co-step" key={i}>
                      <div className="co-step-num">{i + 1}</div>
                      <span className="co-step-text">{step}</span>
                    </div>
                  ))}
                </div>

                <button className="co-qr-confirm" onClick={handleQrConfirm}>
                  ✅ I Have Paid — Confirm Order
                </button>
                <div className="co-qr-note">Click only after completing payment in your UPI app</div>
              </div>
            )}

            {/* ══ CARD / NET BANKING ══ */}
            {tab === "card" && <>
              <div className="co-method-grid">
                {[
                  { icon: "💳", name: "Debit Card",  sub: "Visa • Mastercard • RuPay" },
                  { icon: "🏦", name: "Net Banking", sub: "SBI • HDFC • ICICI • Axis" },
                  { icon: "🪙", name: "Credit Card", sub: "All major cards accepted" },
                  { icon: "👛", name: "Wallets",     sub: "Paytm • Amazon Pay • Freecharge" },
                ].map((m, i) => (
                  <div className="co-mbox" key={i}>
                    <div className="co-micon">{m.icon}</div>
                    <div className="co-mname">{m.name}</div>
                    <div className="co-msub">{m.sub}</div>
                  </div>
                ))}
              </div>
              <button className="co-pay-btn" onClick={handleRazorpay} disabled={loading}>
                {loading ? "⏳ Opening payment window…" : `🔐 Pay ₹${amount.toLocaleString("en-IN")} Securely`}
              </button>
            </>}

            {/* Security */}
            <div className="co-sec">
              {["🔒 256-bit SSL", "✅ RBI Approved", "🛡️ PCI DSS"].map((b, i) => (
                <span className="co-badge" key={i}>{b}</span>
              ))}
            </div>
            <div className="co-powered">
              Powered by <strong>Razorpay</strong> — India's #1 Payment Gateway
            </div>
          </div>

          {/* Trust Strip */}
          <div className="co-trust" style={{ borderRadius: "var(--radius)", marginBottom: 8 }}>
            {[
              { icon: "🚚", text: "Free Delivery on all orders" },
              { icon: "↩️", text: "Easy 7-day returns" },
              { icon: "💚", text: "Vet-approved products" },
              { icon: "📞", text: "24/7 Pet care support" },
            ].map((t, i) => (
              <div className="co-trust-item" key={i}>
                <span className="co-trust-icon">{t.icon}</span>
                <span>{t.text}</span>
              </div>
            ))}
          </div>

          <button className="co-back" onClick={() => navigate("/cart")}>
            ← Back to Cart
          </button>
        </div>

        <div className={`co-toast ${showToast ? "show" : ""}`}>{toast}</div>
      </div>
    </>
  );
}
